/**
 * Generate SQL for a single quiz
 */
function generateQuizSql({ slug, title, description, passingScore, }) {
    const id = CORRECT_QUIZ_IDS[slug] || 'ERROR_MISSING_ID';
    if (id === 'ERROR_MISSING_ID') {
        console.error(`Missing ID for quiz with slug: ${slug}`);
    }
    return `-- Insert quiz: ${title}
INSERT INTO payload.course_quizzes (
  id,
  title,
  slug,
  description,
  passing_score,
  created_at,
  updated_at
) VALUES (
  '${id}', -- UUID for the quiz
  '${title.replace(/'/g, "''")}',
  '${slug}',
  '${description.replace(/'/g, "''")}',
  ${passingScore}, 
  NOW(),
  NOW()
) ON CONFLICT (id) DO NOTHING; -- Skip if the quiz already exists

`;
}
/**
 * Write the fixed SQL file
 * @param outputPath Path to write the SQL file to
 */
export function writeFixedQuizzesSql(outputPath) {
    const sql = generateFixedQuizzesSql();
    fs.writeFileSync(outputPath, sql);
    console.log(`Fixed quiz IDs written to ${outputPath}`);
}
// Main function
export function fixQuizIdConsistency() {
    console.log('Fixing quiz ID consistency...');
    // Path to the output file - ensure we use the project root
    // Find the project root by going back from the current file location
    const projectRoot = path.resolve(fileURLToPath(import.meta.url), '../../../../..');
    const outputDir = path.join(projectRoot, 'apps/payload/src/seed/sql');
    const outputPath = path.join(outputDir, '03-quizzes.sql');
    // Ensure the output directory exists
    if (!fs.existsSync(outputDir)) {
        fs.mkdirSync(outputDir, { recursive: true });
    }
    // Write the fixed SQL file
    writeFixedQuizzesSql(outputPath);
    console.log('Quiz ID consistency fix completed successfully!');
}
// Check if this file is being run directly
const isMainModule = process.argv[1] === fileURLToPath(import.meta.url);
if (isMainModule) {
    fixQuizIdConsistency();
}
